/*
 * Combinational Circuits: Multiplexer and Demultiplexer
 * Multiplexer: Selects one of many inputs to route to single output
 * Demultiplexer: Routes single input to one of many outputs
 */

#include <stdio.h>
#include <math.h>

/*
 * 2:1 Multiplexer
 * Selects between two inputs based on select line
 * Output = I0 when S=0, Output = I1 when S=1
 */
int mux_2to1(int I0, int I1, int S) {
 // Implementation using ternary operator (behavior of MUX)
 return S ? I1 : I0;
 // Equivalent gate implementation: (I0 & ~S) | (I1 & S)
}

/*
 * 4:1 Multiplexer
 * Four data inputs (I0-I3), two select lines (S0-S1)
 * Selects one of four inputs based on binary select value
 */
int mux_4to1(int I0, int I1, int I2, int I3, int S0, int S1) {
 int select = (S1 << 1) | S0; // Combine select lines to get 0-3

 switch(select) {
 case 0: return I0; // S1S0 = 00
 case 1: return I1; // S1S0 = 01
 case 2: return I2; // S1S0 = 10
 case 3: return I3; // S1S0 = 11
 default: return 0;
 }
 // Gate-level: (I0 & ~S1 & ~S0) | (I1 & ~S1 & S0) | 
 // (I2 & S1 & ~S0) | (I3 & S1 & S0)
}

/*
 * 1:2 Demultiplexer
 * Routes single input to one of two outputs based on select
 */
void demux_1to2(int input, int S, int *Y0, int *Y1) {
 *Y0 = input & ~S; // Output Y0 when S=0
 *Y1 = input & S; // Output Y1 when S=1
}

/*
 * 1:4 Demultiplexer
 * Routes single input to one of four outputs
 */
void demux_1to4(int input, int S0, int S1, int *Y0, int *Y1, int *Y2, int *Y3) {
 int select = (S1 << 1) | S0;

 // Clear all outputs first
 *Y0 = *Y1 = *Y2 = *Y3 = 0;

 switch(select) {
 case 0: *Y0 = input; break;
 case 1: *Y1 = input; break;
 case 2: *Y2 = input; break;
 case 3: *Y3 = input; break;
 }
 // Gate-level: Each output = input & appropriate minterm of S1,S0
}

/*
 * 8:1 Multiplexer using 4:1 MUXes (multi-level implementation)
 * Demonstrates multi-level combinational circuit design
 */
int mux_8to1(int *inputs, int S0, int S1, int S2) {
 // First level: two 4:1 MUXes
 int lower_mux = mux_4to1(inputs[0], inputs[1], inputs[2], inputs[3], S0, S1);
 int upper_mux = mux_4to1(inputs[4], inputs[5], inputs[6], inputs[7], S0, S1);

 // Second level: 2:1 MUX to select between the two 4:1 outputs
 return mux_2to1(lower_mux, upper_mux, S2);
}

int main() {
 printf("=== MULTIPLEXER AND DEMULTIPLEXER ===\n\n");

 // Test 4:1 MUX
 printf("4:1 MULTIPLEXER\n");
 printf("S1 S0 | I3 I2 I1 I0 | Output\n");
 printf("--------------------------\n");

 int I0 = 0, I1 = 1, I2 = 0, I3 = 1; // Input values
 for (int s1 = 0; s1 <= 1; s1++) {
 for (int s0 = 0; s0 <= 1; s0++) {
 int output = mux_4to1(I0, I1, I2, I3, s0, s1);
 printf(" %d %d | %d %d %d %d | %d\n", 
 s1, s0, I3, I2, I1, I0, output);
 }
 }

 // Test 1:4 DEMUX
 printf("\n1:4 DEMULTIPLEXER\n");
 printf("Input | S1 S0 | Y3 Y2 Y1 Y0\n");
 printf("-----------------------------\n");

 int input = 1;
 for (int s1 = 0; s1 <= 1; s1++) {
 for (int s0 = 0; s0 <= 1; s0++) {
 int Y0, Y1, Y2, Y3;
 demux_1to4(input, s0, s1, &Y0, &Y1, &Y2, &Y3);
 printf(" %d | %d %d | %d %d %d %d\n", 
 input, s1, s0, Y3, Y2, Y1, Y0);
 }
 }

 // Test 8:1 MUX
 printf("\n8:1 MULTIPLEXER (Multi-level)\n");
 int inputs[8] = {0, 1, 0, 1, 1, 0, 1, 0};
 printf("Inputs: [");
 for (int i = 0; i < 8; i++) printf("%d ", inputs[i]);
 printf("]\n\n");

 for (int s2 = 0; s2 <= 1; s2++) {
 for (int s1 = 0; s1 <= 1; s1++) {
 for (int s0 = 0; s0 <= 1; s0++) {
 int output = mux_8to1(inputs, s0, s1, s2);
 int select = (s2 << 2) | (s1 << 1) | s0;
 printf("Select %d (S2S1S0=%d%d%d): Output = %d\n", 
 select, s2, s1, s0, output);
 }
 }
 }

 return 0;
}
